mapper.select:
SELECT DISTINCT sc.SUBJ_CL_ID, sc.SUBJ_CL_NM, i.INSTR_UUID, m.USER_NAME, i.INSTR_PROFILE_IMG FROM SUBJECT_CLASSIFICATION sc JOIN SUBJECT s ON s.SUBJ_CL_ID = sc.SUBJ_CL_ID JOIN COURSE c ON c.SUBJ_ID = s.SUBJ_ID JOIN INSTRUCTOR i ON i.INSTR_USER_ID = c.INSTR_USER_ID JOIN MEMBER m ON m.USER_ID = i.INSTR_USER_ID WHERE sc.USE_YN = 'Y' AND m.ENABLE = 'Y'
AND sc.SUBJ_CL_ID = #{subjClId}
ORDER BY sc.SUBJ_CL_ID, m.USER_NAME
